import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_withTrueBoolean_writesTrue() throws IOException {
    JsonWriter result = jsonWriter.value(true);
    assertSame(jsonWriter, result);
    assertEquals("true", stringWriter.toString());
  }

  @Test
  public void value_withFalseBoolean_writesFalse() throws IOException {
    JsonWriter result = jsonWriter.value(false);
    assertSame(jsonWriter, result);
    assertEquals("false", stringWriter.toString());
  }

  @Test
  public void value_withNullBoolean_callsNullValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    // Use spy to verify nullValue is called and value returns nullValue's result
    JsonWriter spyWriter = spy(jsonWriter);

    // Stub nullValue to return spyWriter for verification
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.value((Boolean) null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  public void writeDeferredName_and_beforeValue_areCalled_beforeWriting() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);

    // We need to set deferredName to non-null to trigger writeDeferredName writing something
    // Use reflection to set private deferredName field
    var deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(spyWriter, "myName");

    // push a state on stack to avoid exceptions in writeDeferredName or beforeValue
    var stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(spyWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    var stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyWriter, 1);

    // Spy writeDeferredName and beforeValue to verify call order
    doCallRealMethod().when(spyWriter).writeDeferredName();
    doCallRealMethod().when(spyWriter).beforeValue();

    spyWriter.value(true);

    var inOrder = inOrder(spyWriter);
    inOrder.verify(spyWriter).writeDeferredName();
    inOrder.verify(spyWriter).beforeValue();
  }

  @Test
  public void beforeValue_privateMethod_invocation() throws Exception {
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // push a state on stack to avoid exceptions
    var stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    var stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    // Invoke private method beforeValue directly
    beforeValueMethod.invoke(jsonWriter);
  }

  @Test
  public void writeDeferredName_privateMethod_invocation() throws Exception {
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    // Set deferredName to non-null to test writing
    var deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(jsonWriter, "name");

    // push a state on stack to avoid exceptions
    var stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    var stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    writeDeferredNameMethod.invoke(jsonWriter);

    String output = stringWriter.toString();
    assertTrue(output.contains("name"));
  }
}
